return $input.all().map(item => {
  const row = item.json;
  const generatedAt = new Date().toLocaleString('ko-KR', { timeZone: 'Asia/Seoul' });
  return { json: {
    ContentId: row.ContentId,
    TopicId: row.TopicId,
    Category: row.Category,
    ExpectedProfitScore: row.ExpectedProfitScore,
    Title: row.Title,
    Format: row.Format,
    RiskFlag: row.RiskFlag,
    OwnerDecision: row.OwnerDecision,
    SourceRowNumber: row.row_number,
    DraftHook: '회사원이 바로 써볼 만한 AI 업무 도구 5개를 비교했습니다.',
    DraftBody: '오늘 주제는 ' + row.Title + '입니다. 비교 기준은 반복업무 절감, 가격 확인 필요성, 실제 업무 적용 가능성, 자동화 난이도입니다. 먼저 회의록 자동화, 문서 작성 보조, 리서치 보조, 영상 제작 보조, 자동화 연결 도구 순서로 비교합니다. 선택 기준은 매일 반복되는 업무를 실제로 줄여주는지입니다.',
    DraftCTA: '비교표를 보고 본인 업무에 맞는 도구부터 하나만 테스트하세요.',
    RiskReviewStatus: 'DISCLOSURE_REQUIRED',
    GeneratedAt: generatedAt,
    FinalStatus: 'DRAFT_READY'
  }};
});
